  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Task: Translate and LOCALIZE the content for Amazon listing into "${targetLang}".

    [STRICT RULES]
    1. Translate Title, 5 Bullets, Description, and Keywords.
