                          >
                            {m.flag} {m.code}
                            {isTranslating && <Loader2 size={10} className="animate-spin" />}
                          </button>
                        );
                      })}
                   </div>
                   <button 
                    onClick={handleBatchTranslate} 
                    disabled={isBatchTranslating} 
                    className="p-3.5 bg-indigo-50 text-indigo-600 rounded-2xl hover:bg-indigo-100 transition-all shadow-sm shrink-0 border border-indigo-100 flex items-center gap-2 font-black text-[10px] uppercase tracking-widest min-w-[140px] justify-center"
                   >
                      {isBatchTranslating ? <Loader2 size={16} className="animate-spin" /> : <Languages size={16} />} 
                      <span>{batchStatus || 'Translate All'}</span>
