                            <input value={getFieldValue('optimized_weight_unit', 'item_weight_unit')} onChange={e => updateField('optimized_weight_unit', e.target.value)} className="w-24 px-2 py-3 bg-white border border-slate-200 rounded-xl font-black text-[10px] text-center" placeholder="Unit" />
