import { GoogleGenAI, Type } from "@google/genai";
import { CleanedData, OptimizedData } from "../types";

export const optimizeListingWithAI = async (cleanedData: CleanedData): Promise<OptimizedData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    You are an expert Amazon Listing Optimizer. 
    Source Data: ${JSON.stringify(cleanedData)}

    [CORE REQUIREMENTS]
    1. Title: SEO-rich, max 200 chars.
    2. Bullets: Exactly 5 points. EACH UNDER 250 CHARACTERS. MUST START with a [KEYWORD] or [PHRASE].
    3. Description: HTML format, 1000-1500 chars.
    4. Logistics: 
       - Extract weight value as a pure number (e.g., "3.5").
       - Extract weight unit as a standard full word (e.g., "Pounds", "Kilograms").
       - Split dimensions into length, width, height as pure numbers.
       - Extract size unit as a standard full word (e.g., "Inches", "Centimeters").

    [STRICT PROHIBITIONS]
    - NO BRAND NAMES.
    - NO EXTREME WORDS (Best, Perfect, etc.).
    - NO AUTOMOTIVE BRANDS (Toyota, Tesla, etc.).

    Return ONLY JSON matching the schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: { 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimized_title: { type: Type.STRING },
            optimized_features: { type: Type.ARRAY, items: { type: Type.STRING } },
            optimized_description: { type: Type.STRING },
            search_keywords: { type: Type.STRING },
            optimized_weight_value: { type: Type.STRING, description: "Numeric value only" },
            optimized_weight_unit: { type: Type.STRING, description: "Full unit name, e.g. Pounds" },
            optimized_length: { type: Type.STRING, description: "Numeric value only" },
            optimized_width: { type: Type.STRING, description: "Numeric value only" },
            optimized_height: { type: Type.STRING, description: "Numeric value only" },
            optimized_size_unit: { type: Type.STRING, description: "Full unit name, e.g. Inches" }
          },
          required: ["optimized_title", "optimized_features", "optimized_description"]
        }
      }
    });

    const data = JSON.parse(response.text || "{}") as OptimizedData;
    // 补齐 5 个五点描述
    if (data.optimized_features && data.optimized_features.length < 5) {
      while (data.optimized_features.length < 5) data.optimized_features.push("");
    }
    return data;
  } catch (error: any) {
    if (error.message?.includes("Requested entity was not found.")) {
      (window as any).aistudio?.openSelectKey();
    }
    throw error;
  }
};

export const translateListingWithAI = async (sourceData: OptimizedData, targetLangName: string): Promise<Partial<OptimizedData>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `
    Translate this Amazon listing to "${targetLangName}". 
    Maintain all HTML tags in description.
    Keep the [KEYWORD] prefix style in bullet points.
    Do NOT translate brand names if any exist.
    Source: ${JSON.stringify(sourceData)}
  `;
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: { 
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            optimized_title: { type: Type.STRING },
            optimized_features: { type: Type.ARRAY, items: { type: Type.STRING } },
            optimized_description: { type: Type.STRING },
            search_keywords: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) { throw error; }
};

export const editImageWithAI = async (base64Image: string, prompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ inlineData: { mimeType: 'image/jpeg', data: base64Image } }, { text: prompt }] },
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return part.inlineData.data;
    }
    throw new Error("No image data");
  } catch (error) { throw error; }
};

